import{c as e,Q as r,j as a,m as i}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"PARNESS: A Paper Harness for End-to-End Automated Scientific Research with Dynamic Workflows, Full-Text Indexing, and Cross-Run Knowledge Accumulation","description":"","frontmatter":{"title":"PARNESS: A Paper Harness for End-to-End Automated Scientific Research with Dynamic Workflows, Full-Text Indexing, and Cross-Run Knowledge Accumulation","authors":"Yuchen Wang, Zhongzhi Luan","published":"2026-05-06T00:00:00.000Z","source":"https://arxiv.org/abs/2605.05258"},"headers":[],"relativePath":"research/papers/2026-05-06-parness-automated-scientific-research-2605-05258.md","filePath":"research/papers/2026-05-06-parness-automated-scientific-research-2605-05258.md","lastUpdated":1779901665000}'),o={name:"research/papers/2026-05-06-parness-automated-scientific-research-2605-05258.md"};function n(s,t,d,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="parness-a-paper-harness-for-end-to-end-automated-scientific-research" tabindex="-1">PARNESS: A Paper Harness for End-to-End Automated Scientific Research <a class="header-anchor" href="#parness-a-paper-harness-for-end-to-end-automated-scientific-research" aria-label="Permalink to &quot;PARNESS: A Paper Harness for End-to-End Automated Scientific Research&quot;">​</a></h1><p><strong>Authors</strong>: Yuchen Wang (Sino-German Joint Software Institute, Beihang University), Zhongzhi Luan (Beihang University) <strong>Published</strong>: May 6, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.05258" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.05258</a><strong>arXiv ID</strong>: 2605.05258 <strong>Categories</strong>: cs.SE <strong>Code</strong>: <a href="https://github.com/gtrhythm/PARNESS" target="_blank" rel="noreferrer">https://github.com/gtrhythm/PARNESS</a> (~62.2k LoC core + 13.4k LoC tests; 553 passing tests)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>PARNESS is an open-source framework addressing five structural limitations in existing autonomous research systems. Current systems impose fixed control-flow shapes, bounded ideation, episodic reading, overlooked code-repository links, and non-retrievable cross-run knowledge. PARNESS provides &quot;a thin runtime that binds heterogeneous research components into a single declarative pipeline&quot; through four design moves: a customizable DAG kernel, full-text PDF parsing with graceful fallback, a knowledge graph indexing papers/ideas/experiments/code, and GUI/TUI extensibility.</p><hr><h2 id="five-structural-limitations-addressed-l1–l5" tabindex="-1">Five Structural Limitations Addressed (L1–L5) <a class="header-anchor" href="#five-structural-limitations-addressed-l1–l5" aria-label="Permalink to &quot;Five Structural Limitations Addressed (L1–L5)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Limitation</th><th>Impact</th></tr></thead><tbody><tr><td><strong>L1</strong></td><td>Hard-coded workflows fail across disciplines</td><td>Wet-lab, surveys, simulations, theory each iterate differently</td></tr><tr><td><strong>L2</strong></td><td>LLM ideation constrained by context windows + &quot;lost-in-the-middle&quot;</td><td>Limits cross-domain creativity</td></tr><tr><td><strong>L3</strong></td><td>Papers parsed once, then forgotten</td><td>Abstract-only systems miss critical implementation details</td></tr><tr><td><strong>L4</strong></td><td>Paper-to-code links exist per-task only</td><td>No corpus-level indexing for knowledge transfer</td></tr><tr><td><strong>L5</strong></td><td>Each pipeline run starts from zero</td><td>Accumulated knowledge from prior runs remains inaccessible</td></tr></tbody></table><hr><h2 id="design-principles-p1–p6" tabindex="-1">Design Principles (P1–P6) <a class="header-anchor" href="#design-principles-p1–p6" aria-label="Permalink to &quot;Design Principles (P1–P6)&quot;">​</a></h2><ol><li><strong>Domain-agnostic scheduler</strong> — sees only nodes and edges</li><li><strong>Composition as data</strong> — YAML pipelines, not Python code</li><li><strong>Failure isolation</strong> — subprocess slots release GPU memory after each node</li><li><strong>Knowledge persistence</strong> — state survives across runs in SQLite + Neo4j</li><li><strong>LLM interchangeability</strong> — six-provider factory behind unified interface</li><li><strong>Verification as typed output</strong> — experiments emit results + verifier outputs</li></ol><hr><h2 id="four-method-pillars-m1–m4" tabindex="-1">Four Method Pillars (M1–M4) <a class="header-anchor" href="#four-method-pillars-m1–m4" aria-label="Permalink to &quot;Four Method Pillars (M1–M4)&quot;">​</a></h2><h3 id="m1-dag-kernel-dsl" tabindex="-1">M1: DAG Kernel + DSL <a class="header-anchor" href="#m1-dag-kernel-dsl" aria-label="Permalink to &quot;M1: DAG Kernel + DSL&quot;">​</a></h3><p>A ~600-line <code>GraphRunner</code> with a four-field Agent contract enables discipline-agnostic scheduling. Pipelines are YAML with layered validation (schema, contract, type, topology).</p><p><strong>Four-Field Agent Contract:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>_route</code></td><td>string</td><td>Single successor node ID</td></tr><tr><td><code>_routes</code></td><td>array</td><td>One-to-many fan-out</td></tr><tr><td><code>_score</code></td><td>number</td><td>Iteration/ranking value</td></tr><tr><td><code>_metadata</code></td><td>object</td><td>Provenance + free-form data</td></tr></tbody></table><h3 id="m2-full-text-pdf-parsing" tabindex="-1">M2: Full-Text PDF Parsing <a class="header-anchor" href="#m2-full-text-pdf-parsing" aria-label="Permalink to &quot;M2: Full-Text PDF Parsing&quot;">​</a></h3><p>PDF-Extract-Kit integration produces typed layout, formula, OCR, and table objects with provenance. Graceful degradation to abstract-only when full text unavailable; &quot;abstract-comprehension&quot; capability grows with cumulative corpus.</p><h3 id="m3-knowledge-graph-cognitive-roles" tabindex="-1">M3: Knowledge Graph + Cognitive Roles <a class="header-anchor" href="#m3-knowledge-graph-cognitive-roles" aria-label="Permalink to &quot;M3: Knowledge Graph + Cognitive Roles&quot;">​</a></h3><p>Neo4j stores papers, ideas, experiments, and code repositories as typed nodes with four edge types (structural, internal, semantic, walk).</p><p><strong>Six cognitive-role agents</strong>: Reader, Analyst, Connector, Contrarian, Synthesizer, Critic — retrieve scenario-typed slices (similar / opposite / cross-domain / counter-intuitive).</p><p><strong>Knowledge Graph Indexing (Eight Phases):</strong></p><ol><li>Extract (LLM)</li><li>Dedup (deterministic)</li><li>Embed (deterministic)</li><li>Write nodes (deterministic)</li><li>Internal edges (LLM)</li><li>Structural edges (deterministic)</li><li>Semantic edges (LLM)</li><li>Random walk (deterministic)</li></ol><h3 id="m4-gui-tui-extension-surface" tabindex="-1">M4: GUI/TUI Extension Surface <a class="header-anchor" href="#m4-gui-tui-extension-surface" aria-label="Permalink to &quot;M4: GUI/TUI Extension Surface&quot;">​</a></h3><p>Single-file modules with <code>@register</code> decorator + single-document YAML pipelines + self-describing <code>INPUT_SPEC</code>/<code>OUTPUT_SPEC</code> enable external coding agents (Claude Code, Cursor, Copilot) to modify workflows without custom plugins.</p><hr><h2 id="system-architecture-four-layers" tabindex="-1">System Architecture (Four Layers) <a class="header-anchor" href="#system-architecture-four-layers" aria-label="Permalink to &quot;System Architecture (Four Layers)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Components</th></tr></thead><tbody><tr><td><strong>L0 (DAG Kernel)</strong></td><td>GraphRunner, BaseModule contract, ModuleRegistry (~600 LoC)</td></tr><tr><td><strong>L1 (Persistence)</strong></td><td>Five SQLite stores (papers, knowledge, evaluations, writing, experiments) + Neo4j with vector index</td></tr><tr><td><strong>L2 (Agents)</strong></td><td>25+ domain agents, 130+ adapters, six LLM providers, domain tools (PDF parser, KG, crawlers, experiment runner)</td></tr><tr><td><strong>L3 (Pipeline)</strong></td><td>~50 YAML pipelines, entry-point scripts, four-pass pipeline validator</td></tr></tbody></table><hr><h2 id="module-taxonomy-130-modules" tabindex="-1">Module Taxonomy (130+ modules) <a class="header-anchor" href="#module-taxonomy-130-modules" aria-label="Permalink to &quot;Module Taxonomy (130+ modules)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Count</th></tr></thead><tbody><tr><td>Research/crawler/parser</td><td>8</td></tr><tr><td>Ideation</td><td>26</td></tr><tr><td>Experiment runner/verifier</td><td>24</td></tr><tr><td>Writing &amp; review</td><td>11</td></tr><tr><td>Knowledge graph</td><td>17</td></tr><tr><td>Infrastructure</td><td>16+</td></tr><tr><td>Iteration controllers</td><td>7</td></tr><tr><td>Post-processing</td><td>2</td></tr></tbody></table><hr><h2 id="discipline-specific-pipeline-examples" tabindex="-1">Discipline-Specific Pipeline Examples <a class="header-anchor" href="#discipline-specific-pipeline-examples" aria-label="Permalink to &quot;Discipline-Specific Pipeline Examples&quot;">​</a></h2><p>All four pipelines run on the same DAG kernel — demonstrating L1 compliance:</p><ul><li><strong>ML benchmark loop</strong>: idea → gate → experiment loop</li><li><strong>Wet-lab biology</strong>: hypothesis → idea-discussion → peer-gate → protocol → biosafety → wet-lab → replicate → stat-gate</li><li><strong>Social-science survey</strong>: RQ → instrument → pilot → IRB → recruit → coding → analyse → revise</li><li><strong>Theory+simulation</strong>: parallel proof attempts and parameter sweeps with evidence merging</li></ul><hr><h2 id="related-work-comparison" tabindex="-1">Related Work Comparison <a class="header-anchor" href="#related-work-comparison" aria-label="Permalink to &quot;Related Work Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>System</th><th>Workflow shape</th><th>Full-text reading</th><th>Cross-run knowledge</th></tr></thead><tbody><tr><td>AI-Scientist v1/v2</td><td>Linear or four-stage; template-dependent</td><td>No</td><td>No</td></tr><tr><td>PaperOrchestra</td><td>Fixed five-step recipe</td><td>Abstract-only</td><td>No</td></tr><tr><td>AutoSOTA</td><td>Post-publication optimization only</td><td>No</td><td>No</td></tr><tr><td>InternAgent</td><td>Eleven-state WorkflowState enum</td><td>No</td><td>No</td></tr><tr><td><strong>PARNESS</strong></td><td><strong>Data-defined DAG topology</strong></td><td><strong>Full PDF + graceful fallback</strong></td><td><strong>SQLite + Neo4j across runs</strong></td></tr></tbody></table><hr><h2 id="llm-providers" tabindex="-1">LLM Providers <a class="header-anchor" href="#llm-providers" aria-label="Permalink to &quot;LLM Providers&quot;">​</a></h2><p>OpenAI, Anthropic, GLM (Zhipu), MiniMax, Local, MockLLM (4,444 rule-based canned responses for offline testing).</p><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>&quot;Empirically the parallel ensemble produces wider seed coverage than a single LLM at the same total token budget; we have not yet measured this rigorously&quot;</li><li>No shared benchmark comparison with AI-Scientist, InternAgent, or PaperOrchestra</li><li>No production-scale evaluation, user studies, or domain generalization evidence</li><li>Self-declared &quot;v1 systems paper&quot; without comparative quality metrics</li></ul><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>PARNESS Design Move</th><th>cc-workspace Relevance</th><th>Priority</th></tr></thead><tbody><tr><td>DAG kernel for agent orchestration</td><td>Parallels hierarchical sub-agent topology in <code>subagent-strategy.md</code></td><td>Medium</td></tr><tr><td>YAML-defined pipelines as data</td><td>Aligns with declarative config preference over code</td><td>Low (already implicit)</td></tr><tr><td>Full-text PDF indexing across papers</td><td>Useful if <code>research/papers/</code> corpus grows to 50+ files</td><td>Medium-term</td></tr><tr><td>Cross-run knowledge via SQLite/Neo4j</td><td>Heavy infrastructure; overkill for current workspace scale</td><td>Low</td></tr><tr><td>MockLLM (4,444 canned responses)</td><td>Interesting pattern for offline harness testing</td><td>Medium (test infra)</td></tr><tr><td>Cognitive-role agents for retrieval</td><td>Contrarian + Synthesizer roles align with advisor() use cases</td><td>Conceptual alignment</td></tr></tbody></table><hr><h2 id="key-citation" tabindex="-1">Key Citation <a class="header-anchor" href="#key-citation" aria-label="Permalink to &quot;Key Citation&quot;">​</a></h2><blockquote><p>&quot;PARNESS proposes a thin runtime that binds heterogeneous research components into a single declarative pipeline — a minimal DAG kernel plus four structured design moves addressing workflow rigidity, bounded ideation, episodic reading, unindexed code links, and zero cross-run memory.&quot; (arXiv:2605.05258)</p></blockquote>',51)])])}const g=e(o,[["render",n]]);export{p as __pageData,g as default};
